import{_ as a,o as i,c as t,ao as s}from"./chunks/framework.gCxX98A5.js";const u=JSON.parse('{"title":"FAQ","description":"","frontmatter":{},"headers":[],"relativePath":"faq.md","filePath":"faq.md","lastUpdated":null}'),r={name:"faq.md"};function n(o,e,l,h,d,c){return i(),t("div",null,[...e[0]||(e[0]=[s('<h1 id="FAQ" tabindex="-1">FAQ <a class="header-anchor" href="#FAQ" aria-label="Permalink to &quot;FAQ {#FAQ}&quot;">​</a></h1><h2 id="Why-are-spherical-and-cylindrical-geometries-CPU-only?" tabindex="-1">Why are spherical and cylindrical geometries CPU-only? <a class="header-anchor" href="#Why-are-spherical-and-cylindrical-geometries-CPU-only?" aria-label="Permalink to &quot;Why are spherical and cylindrical geometries CPU-only? {#Why-are-spherical-and-cylindrical-geometries-CPU-only?}&quot;">​</a></h2><p><a href="/cDFT.jl/dev/structures#cDFT.Uniform1DSphr"><code>Uniform1DSphr</code></a> and <a href="/cDFT.jl/dev/structures#cDFT.Uniform1DCyl"><code>Uniform1DCyl</code></a> use a quasi-discrete Hankel transform (<a href="https://github.com/jwscook/Hankel.jl" target="_blank" rel="noreferrer">Hankel.jl</a>) rather than an FFT to perform radial convolutions, and that implementation does not currently run on the GPU. If you need a curved geometry on the GPU, embed it in a Cartesian box instead (e.g. <a href="/cDFT.jl/dev/structures#cDFT.TwoPhase3DSphrCart"><code>TwoPhase3DSphrCart</code></a> for a spherical droplet) — see <a href="/cDFT.jl/dev/tutorials/geometries#Choosing-a-Geometry-and-Adsorption">Choosing a Geometry &amp; Adsorption</a>.</p><h2 id="Why-did-my-density-profile-turn-into-NaN?" tabindex="-1">Why did my density profile turn into <code>NaN</code>? <a class="header-anchor" href="#Why-did-my-density-profile-turn-into-NaN?" aria-label="Permalink to &quot;Why did my density profile turn into `NaN`? {#Why-did-my-density-profile-turn-into-NaN?}&quot;">​</a></h2><p>The most common cause is a density that underflows to an exact <code>0.0</code> right at a hard wall or excluded-volume boundary: <code>log</code>/association terms in the free-energy functional produce <code>NaN</code> for exactly-zero density, and this then spreads to the entire profile after one convolution pass. Wall-type external fields (e.g. <a href="/cDFT.jl/dev/external_fields#cDFT.Steele"><code>Steele</code></a>) clamp the minimum wall distance to <code>0.5*minimum(σ)</code> for exactly this reason — if you&#39;re writing a custom external field, make sure it does the same near any hard boundary.</p><h2 id="Why-is-my-first-calculation-so-slow?" tabindex="-1">Why is my first calculation so slow? <a class="header-anchor" href="#Why-is-my-first-calculation-so-slow?" aria-label="Permalink to &quot;Why is my first calculation so slow? {#Why-is-my-first-calculation-so-slow?}&quot;">​</a></h2><p>Model free-energy kernels are automatically differentiated with <a href="https://github.com/EnzymeAD/Enzyme.jl" target="_blank" rel="noreferrer">Enzyme.jl</a> and compiled the first time they&#39;re called for a given model/structure/device combination — this one-time compilation can take anywhere from several seconds to a few minutes for the more complex functionals (e.g. electrolyte models), independent of the actual convergence time. Subsequent calls with the same types are fast. If you&#39;re iterating on a script, keep a persistent Julia session (e.g. via <a href="https://github.com/timholy/Revise.jl" target="_blank" rel="noreferrer">Revise.jl</a>) rather than restarting Julia for every run.</p><h2 id="Why-do-I-get-an-error-asking-me-to-load-GCIdentifier/ChemicalIdentifiers?" tabindex="-1">Why do I get an error asking me to load <code>GCIdentifier</code>/<code>ChemicalIdentifiers</code>? <a class="header-anchor" href="#Why-do-I-get-an-error-asking-me-to-load-GCIdentifier/ChemicalIdentifiers?" aria-label="Permalink to &quot;Why do I get an error asking me to load `GCIdentifier`/`ChemicalIdentifiers`? {#Why-do-I-get-an-error-asking-me-to-load-GCIdentifier/ChemicalIdentifiers?}&quot;">​</a></h2><p>Resolving group-contribution connectivity automatically from a SMILES string or chemical name (rather than a hand-written <a href="/cDFT.jl/dev/api/utils#cDFT.custom_structure"><code>custom_structure</code></a>) is implemented as a package extension. Add and load both packages:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;" class="repl-prompt repl-prompt-julia">julia</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;" class="repl-prompt repl-prompt-julia">&gt;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> using</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Pkg; Pkg</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">add</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">([</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;GCIdentifier&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;ChemicalIdentifiers&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">])</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;" class="repl-prompt repl-prompt-julia">julia</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;" class="repl-prompt repl-prompt-julia">&gt;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> using</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> GCIdentifier, ChemicalIdentifiers, cDFT</span></span></code></pre></div><p>See <a href="/cDFT.jl/dev/tutorials/group_contribution_chains#Group-Contribution-and-Heterosegmented-Chains">Group-Contribution &amp; Heterosegmented Chains</a>.</p><h2 id="How-do-I-run-a-calculation-on-the-GPU?" tabindex="-1">How do I run a calculation on the GPU? <a class="header-anchor" href="#How-do-I-run-a-calculation-on-the-GPU?" aria-label="Permalink to &quot;How do I run a calculation on the GPU? {#How-do-I-run-a-calculation-on-the-GPU?}&quot;">​</a></h2><p>Load <code>CUDA</code> <em>before</em> constructing your <a href="/cDFT.jl/dev/api/options#cDFT.DFTOptions"><code>DFTOptions</code></a>, then pass a <code>CUDABackend()</code>:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;" class="repl-prompt repl-prompt-julia">julia</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;" class="repl-prompt repl-prompt-julia">&gt;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> using</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> CUDA</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;" class="repl-prompt repl-prompt-julia">julia</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;" class="repl-prompt repl-prompt-julia">&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> options </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> cDFT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">DFTOptions</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">CUDABackend</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">())</span></span></code></pre></div><p>Remember that spherical/cylindrical structures cannot run on the GPU (see above). See <a href="/cDFT.jl/dev/tutorials/gpu_acceleration#GPU-Acceleration">GPU Acceleration</a> for when GPU acceleration is actually worth the transfer overhead.</p>',15)])])}const m=a(r,[["render",n]]);export{u as __pageData,m as default};
